import{c as t,Q as i,j as n,m as a}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Lost in the Middle: How Language Models Use Long Contexts","description":"","frontmatter":{"title":"Lost in the Middle: How Language Models Use Long Contexts","arxiv_id":2307.03172,"authors":"Nelson F. Liu, Kevin Lin, John Hewitt, Ashwin Paranjape, Michele Bevilacqua, Fabio Petroni, Percy Liang","fetched":"2026-05-12T00:00:00.000Z","published":"2023-07-06T00:00:00.000Z","source":"https://arxiv.org/abs/2307.03172","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-05-12-lost-in-the-middle-2307-03172.md","filePath":"research/papers/2026-05-12-lost-in-the-middle-2307-03172.md","lastUpdated":1779901665000}'),o={name:"research/papers/2026-05-12-lost-in-the-middle-2307-03172.md"};function r(s,e,l,d,c,h){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="lost-in-the-middle-how-language-models-use-long-contexts" tabindex="-1">Lost in the Middle: How Language Models Use Long Contexts <a class="header-anchor" href="#lost-in-the-middle-how-language-models-use-long-contexts" aria-label="Permalink to &quot;Lost in the Middle: How Language Models Use Long Contexts&quot;">​</a></h1><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The researchers examined how effectively language models leverage extended input contexts. Using multi-document question answering and key-value retrieval tasks, they discovered that model performance significantly fluctuates based on where relevant information appears in the input. Their key finding: &quot;performance is often highest when relevant information occurs at the beginning or end of the input context, and significantly degrades when models must access relevant information in the middle.&quot;</p><p>This pattern persisted even in models specifically designed for long-context processing, suggesting systemic limitations in how these systems process mid-document information.</p><hr><h2 id="core-finding" tabindex="-1">Core Finding <a class="header-anchor" href="#core-finding" aria-label="Permalink to &quot;Core Finding&quot;">​</a></h2><p>The paper demonstrates a surprising U-shaped performance curve with respect to the position of relevant information:</p><ul><li><strong>Highest performance:</strong> When relevant information appears at the beginning (start of context) or end (near final tokens)</li><li><strong>Degraded performance:</strong> When models must retrieve information from the middle of extended contexts</li><li><strong>Magnitude:</strong> Performance drops can be substantial even for models explicitly trained for long-context understanding</li></ul><hr><h2 id="key-implications" tabindex="-1">Key Implications <a class="header-anchor" href="#key-implications" aria-label="Permalink to &quot;Key Implications&quot;">​</a></h2><ol><li><p><strong>Architectural Limitation:</strong> The pattern persists across different model architectures and sizes, suggesting it is a fundamental characteristic of how transformers process long sequences</p></li><li><p><strong>Training Limitations:</strong> Even models specifically designed for long-context processing (e.g., models with extended training on long documents) exhibit this behavior</p></li><li><p><strong>Practical Impact:</strong> For applications requiring access to information scattered throughout large documents, current LLMs may struggle with middle-positioned content</p></li></ol><hr><h2 id="evaluation-framework" tabindex="-1">Evaluation Framework <a class="header-anchor" href="#evaluation-framework" aria-label="Permalink to &quot;Evaluation Framework&quot;">​</a></h2><p>The research employs two primary evaluation methodologies:</p><ol><li><strong>Multi-document Question Answering:</strong> Models must find answers distributed across multiple documents with varying lengths and complexity</li><li><strong>Key-Value Retrieval Tasks:</strong> Simple structured tasks where models retrieve specific information from defined positions in the context</li></ol><hr><h2 id="generalization" tabindex="-1">Generalization <a class="header-anchor" href="#generalization" aria-label="Permalink to &quot;Generalization&quot;">​</a></h2><p>The &quot;lost in the middle&quot; phenomenon appears consistent across:</p><ul><li>Different base model families</li><li>Various context lengths</li><li>Different types of content (text, structured data)</li><li>Both retrieval and reasoning tasks</li></ul><hr><h2 id="related-work-and-positioning" tabindex="-1">Related Work and Positioning <a class="header-anchor" href="#related-work-and-positioning" aria-label="Permalink to &quot;Related Work and Positioning&quot;">​</a></h2><p>This work connects to broader research on:</p><ul><li>Long-context language model training and evaluation</li><li>Attention mechanism behavior in transformers</li><li>Information retrieval in extended contexts</li><li>Context-dependent reasoning</li></ul><hr><h2 id="practical-recommendations" tabindex="-1">Practical Recommendations <a class="header-anchor" href="#practical-recommendations" aria-label="Permalink to &quot;Practical Recommendations&quot;">​</a></h2><p>For practitioners deploying LLMs with long contexts:</p><ol><li><strong>Information Placement:</strong> Position critical information at the beginning or end of prompts when possible</li><li><strong>Chunking Strategies:</strong> Consider breaking long documents into overlapping segments to ensure important information isn&#39;t buried in the middle</li><li><strong>Prompting Techniques:</strong> Use explicit markers or hierarchical organization to highlight critical mid-document information</li><li><strong>Model Selection:</strong> Factor in this limitation when evaluating models for long-context applications</li></ol><hr><h2 id="research-impact" tabindex="-1">Research Impact <a class="header-anchor" href="#research-impact" aria-label="Permalink to &quot;Research Impact&quot;">​</a></h2><p>The paper provides important evaluation frameworks for assessing future long-context language model development, establishing a baseline for understanding current limitations and measuring progress on this capability.</p><hr><h2 id="venue" tabindex="-1">Venue <a class="header-anchor" href="#venue" aria-label="Permalink to &quot;Venue&quot;">​</a></h2><p>Transactions of the Association for Computational Linguistics (TACL), 2023</p>',33)])])}const p=t(o,[["render",r]]);export{g as __pageData,p as default};
